1	export interface ItemSpec {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	export interface Customer {
9	  yearsWithMHPCO: number;
10	}
11	
12	export interface QuoteInput {
13	  customer: Customer;
14	  items: ItemSpec[];
15	}
16	
17	export interface QuoteResult {
18	  premium: number;
19	}
20	
21	const PROCESSING_FEE = 5;
22	const FIRST_INSURANCE_RATE = 0.1;
23	const CURSE_SURCHARGE_RATE = 0.5;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
26	const BLOCK_SIZE = 3;
27	const BLOCK_PRICE = 60;
28	const COMPONENT_TYPES = ["rune", "moonstone"];
29	const LOYALTY_YEARS_THRESHOLD = 2;
30	const LOYALTY_DISCOUNT_RATE = 0.2;
31	
32	const BASE_PREMIUMS: Record<string, number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	  rune: 25,
38	  moonstone: 25,
39	};
40	
41	function basePremiumFor(item: ItemSpec): number {
42	  return BASE_PREMIUMS[item.type] ?? 0;
43	}
44	
45	function sumBasePremiums(items: ItemSpec[]): number {
46	  return items.reduce((sum, item) => sum + basePremiumFor(item), 0);
47	}
48	
49	function countItemsOfType(items: ItemSpec[], type: string): number {
50	  return items.filter((item) => item.type === type).length;
51	}
52	
53	function blockAdjustmentFor(items: ItemSpec[], componentType: string): number {
54	  const count = countItemsOfType(items, componentType);
55	  if (count !== BLOCK_SIZE) return 0;
56	  return BLOCK_PRICE - BLOCK_SIZE * BASE_PREMIUMS[componentType];
57	}
58	
59	function blockAdjustment(items: ItemSpec[]): number {
60	  return COMPONENT_TYPES.reduce(
61	    (sum, componentType) => sum + blockAdjustmentFor(items, componentType),
62	    0
63	  );
64	}
65	
66	function isHighlyEnchanted(item: ItemSpec): boolean {
67	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
68	}
69	
70	function itemSurchargeFor(item: ItemSpec): number {
71	  let surcharge = 0;
72	  if (item.cursed) surcharge += basePremiumFor(item) * CURSE_SURCHARGE_RATE;
73	  if (isHighlyEnchanted(item)) surcharge += basePremiumFor(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE;
74	  return surcharge;
75	}
76	
77	function sumItemSurcharges(items: ItemSpec[]): number {
78	  return items.reduce((sum, item) => sum + itemSurchargeFor(item), 0);
79	}
80	
81	function qualifiesForLoyaltyDiscount(customer: Customer): boolean {
82	  return customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
83	}
84	
85	function loyaltyDiscountFor(customer: Customer, policyBasePremium: number): number {
86	  if (!qualifiesForLoyaltyDiscount(customer)) return 0;
87	  return policyBasePremium * LOYALTY_DISCOUNT_RATE;
88	}
89	
90	export function quote(input: QuoteInput): QuoteResult {
91	  const items = input.items;
92	  const policyBasePremium = sumBasePremiums(items) + blockAdjustment(items);
93	  const itemSurcharges = sumItemSurcharges(items);
94	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
95	  const loyaltyDiscount = loyaltyDiscountFor(input.customer, policyBasePremium);
96	  return {
97	    premium: Math.ceil(
98	      policyBasePremium + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount + PROCESSING_FEE
99	    ),
100	  };
101	}
102	
103	export function claim(): unknown {
104	  return undefined;
105	}
